def _wrap(d):
    """Wrap a raw dict (or list/None) into a typed AST node."""
    if d is None:
        return None
    if isinstance(d, list):
        return [_wrap(x) for x in d]
    cls = _NODE_MAP.get(d["type"])
    if cls is not None:
        return cls(d)
    return d
